198	/**
199	 * Searches transactions by description text.
200	 *
201	 * KNOWN PERFORMANCE ISSUE: Creates a new RegExp for every transaction
202	 * and does a linear dedup scan on the results array.
203	 */
204	export function searchTransactions(
205	  transactions: Transaction[],
206	  query: string
207	): Transaction[] {
208	  const results: Transaction[] = [];
209	
210	  for (const transaction of transactions) {
211	    // SLOW: Create a brand new RegExp for every transaction
212	    const pattern = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "i");
213	    const match = pattern.test(transaction.description);
214	
215	    if (match) {
216	      // SLOW: Check if already added by scanning results array
217	      let alreadyAdded = false;
218	      for (const r of results) {
219	        if (r.id === transaction.id) {
220	          alreadyAdded = true;
221	          break;
222	        }
223	      }
224	
225	      if (!alreadyAdded) {
226	        results.push(transaction);
227	      }
228	    }
229	  }
230	
231	  return results;
232	}
