237	export function processAll(
238	  transactions: Transaction[],
239	  topN: number = 10
240	): PipelineResult {
241	  const categoryGroups = groupByCategory(transactions);
242	  const duplicates = findDuplicates(transactions);
243	  const topSpendersList = topSpenders(transactions, topN);
244	
245	  return {
246	    categoryGroups,
247	    duplicates,
248	    topSpenders: topSpendersList,
249	  };
250	}
